import{_ as a,o as s,c as n,a2 as p}from"./chunks/framework.m9rfQn3T.js";const h=JSON.parse('{"title":"淘宝、网易移动端px转rem","description":"","frontmatter":{"title":"淘宝、网易移动端px转rem","date":"2017-06-06T16:06:21.000Z","permalink":"/pages/7d84a3/","categories":["hexo迁移数据"],"author":{"name":"神族九帝","link":"https://github.com/wu529778790","permalink":null,"categories":null},"sidebar":"auto","tags":[null]},"headers":[],"relativePath":"20.笔记/1000.hexo迁移数据/淘宝、网易移动端px转rem.md","filePath":"20.笔记/1000.hexo迁移数据/淘宝、网易移动端px转rem.md","lastUpdated":1782538095000}'),l={name:"20.笔记/1000.hexo迁移数据/淘宝、网易移动端px转rem.md"};function i(t,e,r,o,d,c){return s(),n("div",null,[...e[0]||(e[0]=[p(`<h1 id="网易转换-rem-分析" tabindex="-1">网易转换 rem 分析 <a class="header-anchor" href="#网易转换-rem-分析" aria-label="Permalink to &quot;网易转换 rem 分析&quot;">​</a></h1><p>首先网易的设计稿是基于 iPhone5 设计的也就是宽度 640px。（先不考虑 dpr 的问题下面会说）然后设置 1rem 等于 100px（ HTML font-size 为 100px），相当于 6.4rem = 100%宽度 = 设备的宽度。</p><p>由于是基于 6.4rem 开发。iPhone5 的物理像素是 320px（dpr 是 2.0），如果此时还想让 6.4rem 等于设备宽度只能调整 1rem 对应 font-size 的比例， 320 / 6.4 = 50 让 1rem=50px 就可以实现。如果想让 iPhone6 适配只需要 1rem = （375 / 6.4） = 58.59375px 就可以实现 iPhone6 的适配，这个方法可以适配市面上绝大多数的移动端设备。</p><p>只需要加下面这句话可以实现我上述效果。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>document.documentElement.style.fontSize = document.documentElement.clientWidth / 6.4 + &#39;px&#39;;</span></span></code></pre></div><h1 id="淘宝转换-rem-分析" tabindex="-1">淘宝转换 rem 分析 <a class="header-anchor" href="#淘宝转换-rem-分析" aria-label="Permalink to &quot;淘宝转换 rem 分析&quot;">​</a></h1><p>这次咱们还是拿 iPhone5（640px）的设计稿举例，淘宝的思想是无论当前页面多宽，让 10rem = 页面宽度 = 100%，所以 1rem = 64px 然后通过 dpr 设置缩放整个页面，以达到高保真的效果。</p><p>iPhone5 的宽度是 640px，页面最终完成效果也是 640px，iPhone 的 dpr 是 2，所以设置 &lt;meta name=&quot;viewport&quot; content=&quot;initial-scale=0.5, maximum-scale=0.5, minimum-scale=0.5, user-scalable=no&quot;&gt; 就可以了适配 iPhone5 了。当然这些东西 lib-flexible 都帮我们做好了。我只不过说一下，让好奇的小伙伴知道原理。</p><h2 id="vue-cli-配合-lib-flexible-实现移动端自适应布局" tabindex="-1">Vue-cli 配合 lib-flexible 实现移动端自适应布局 <a class="header-anchor" href="#vue-cli-配合-lib-flexible-实现移动端自适应布局" aria-label="Permalink to &quot;Vue-cli 配合 lib-flexible 实现移动端自适应布局&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cnpm intall lib-flexible  // 安装lib-flexible</span></span>
<span class="line"><span>import &#39;lib-flexible&#39;     // 在 src\\main.js 中引入 lib-flexible</span></span></code></pre></div><p>完成上面代码就相当于实现了 rem 动态计算了，如果此时在 iPhone5 上有一个元素是宽 150px，高是 200px，想计算 rem 宽是 150/64 = 2.34375rem，高是 200/64 = 3.125rem。</p><p>至于 dpr 的缩放问题,那个就不用关心了。lib-flexible 已经帮你做好了。你只需要关心 dpr 转换 rem 即可。</p><h2 id="使用-px2rem-loader-自动将-px-转换-rem" tabindex="-1">使用 px2rem-loader 自动将 px 转换 rem <a class="header-anchor" href="#使用-px2rem-loader-自动将-px-转换-rem" aria-label="Permalink to &quot;使用 px2rem-loader 自动将 px 转换 rem&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cnpm intall px2rem-loader  // 安装px2rem-loader</span></span></code></pre></div><p>在 build\\utils.js 修改成下面的代码。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span> // 在 cssLoaders 方法内添加下列代码</span></span>
<span class="line"><span>  const px2remLoader = {</span></span>
<span class="line"><span>    loader: &#39;px2rem-loader&#39;,</span></span>
<span class="line"><span>    options: {</span></span>
<span class="line"><span>      remUnit: 64 //设计稿宽度/10</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>  // 将 cssLoaders 方法内的generateLoaders的方法内的 loaders 变量添加 px2remLoader</span></span>
<span class="line"><span>  const loaders = options.usePostCSS ? [cssLoader, postcssLoader, px2remLoader, lessLoader ] : [cssLoader, px2remLoader, lessLoader ]</span></span></code></pre></div><p>转：<a href="https://juejin.im/post/5afba3c5f265da0b9e653b6c" target="_blank" rel="noreferrer">https://juejin.im/post/5afba3c5f265da0b9e653b6c</a></p>`,17)])])}const u=a(l,[["render",i]]);export{h as __pageData,u as default};
